import { type ClassValue, clsx } from 'clsx'
import { twMerge } from 'tailwind-merge'

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs))
}

// ── Content layer — maps to Backend MongoDB API ───────────────────────────────
// All article data now comes from the Fastify backend via /api/articles
//
// NOTE: For SSR in Next.js App Router, fetch() uses absolute URLs by default.
// NEXT_PUBLIC_API_URL is set to the backend base URL (e.g. http://localhost:4000).

import { fetchArticles, fetchArticle as fetchArticleApi, fetchAdminArticles, searchArticlesBackend, type ApiArticleSummary, type ApiArticle } from './api'
import type { ArticleSummary } from '@/components/blog/article-card'

// ── Re-export Article type for convenience ────────────────────────────────────
export type { ArticleSummary }

// ── Internal helpers ──────────────────────────────────────────────────────────

/** Full article with content (returned by getArticleBySlug) */
export interface Article extends ArticleSummary {
  content: string
}

/** Map API article summary → frontend ArticleSummary (matches ArticleCard) */
function mapSummary(a: ApiArticleSummary): ArticleSummary {
  return {
    slug: a.slug,
    title: a.title,
    excerpt: a.excerpt ?? '',
    category: a.category ?? 'ctdl',
    tags: Array.isArray(a.tags) ? a.tags : [],
    hero: a.coverImage ?? null,
    author: a.author?.name ?? 'MAIY Tech Hub',
    readingTime: a.readingTime ?? 5,
    publishedAt: a.publishedAt ?? new Date().toISOString(),
  }
}

/** Map API full article → frontend Article (with content) */
function mapArticle(a: ApiArticle): Article {
  return {
    ...mapSummary(a),
    content: a.content ?? '',
  }
}

// ── Public API (mirrors old MDX interface) ───────────────────────────────────

export async function getAllArticles(): Promise<ArticleSummary[]> {
  try {
    const res = await fetchArticles({ limit: 100 })
    return res.articles.map(mapSummary)
  } catch (err) {
    console.error('[content] getAllArticles failed:', err)
    return []
  }
}

/** All tags with article count, sorted by frequency */
export interface TagCount { tag: string; count: number }
export async function getAllTags(): Promise<TagCount[]> {
  try {
    const res = await fetchArticles({ limit: 1000 })
    const tagCounts: Record<string, number> = {}
    for (const a of res.articles) {
      for (const tag of (a.tags ?? [])) {
        tagCounts[tag] = (tagCounts[tag] || 0) + 1
      }
    }
    return Object.entries(tagCounts)
      .map(([tag, count]) => ({ tag, count }))
      .sort((a, b) => b.count - a.count)
  } catch {
    return []
  }
}

/** Search articles by query — uses backend search param + client-side tag filter */
export async function searchArticles(query: string): Promise<ArticleSummary[]> {
  if (!query.trim()) return []
  try {
    // Try backend search first
    const articles = await searchArticlesBackend(query, 50)
    // Backend doesn't search tags, so also filter client-side by tag
    const q = query.toLowerCase()
    return articles
      .filter(
        (a) =>
          a.title.toLowerCase().includes(q) ||
          (a.excerpt ?? '').toLowerCase().includes(q) ||
          (a.tags ?? []).some((t) => t.toLowerCase().includes(q))
      )
      .map(mapSummary)
  } catch {
    return []
  }
}

export async function getRecentArticles(limit = 6): Promise<ArticleSummary[]> {
  try {
    const res = await fetchArticles({ limit })
    return res.articles.map(mapSummary)
  } catch (err) {
    console.error('[content] getRecentArticles failed:', err)
    return []
  }
}

export async function getFeaturedArticles(): Promise<ArticleSummary[]> {
  return getAllArticles()
}

/** Admin: all articles including unpublished */
export async function getAdminArticles(): Promise<ArticleSummary[]> {
  try {
    const articles = await fetchAdminArticles()
    return articles.map(mapSummary)
  } catch (err) {
    console.error('[content] getAdminArticles failed:', err)
    return []
  }
}

export async function getArticleBySlug(slug: string): Promise<(ArticleSummary & { content: string }) | null> {
  try {
    const article = await fetchArticleApi(slug)
    if (!article) return null
    return mapArticle(article)
  } catch (err) {
    console.error(`[content] getArticleBySlug(${slug}) failed:`, err)
    return null
  }
}

export async function getArticlesByCategory(category: string): Promise<ArticleSummary[]> {
  try {
    const res = await fetchArticles({ category, limit: 100 })
    return res.articles.map(mapSummary)
  } catch (err) {
    console.error(`[content] getArticlesByCategory(${category}) failed:`, err)
    return []
  }
}

export async function getAllSlugs(): Promise<string[]> {
  try {
    const res = await fetchArticles({ limit: 1000 })
    return res.articles.map((a) => a.slug)
  } catch (err) {
    console.error('[content] getAllSlugs failed:', err)
    return []
  }
}

// ── API Client for MAIY Tech Hub Backend ──────────────────────────────────────
// Maps frontend to Fastify + MongoDB backend API

const API_URL = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:4000'
const TIMEOUT = Number(process.env.NEXT_PUBLIC_API_TIMEOUT) || 10000

// ── Types ─────────────────────────────────────────────────────────────────────

// ── Backend article shape (from Prisma) ────────────────────────────────────────
export interface ApiArticle {
  id: string
  slug: string
  title: string
  excerpt: string
  content: string
  category: string
  tags: string[]
  coverImage?: string | null
  readingTime: number
  publishedAt: string | null
  published: boolean
  authorId: string
  author: { id: string; name: string; avatar?: string | null }
  createdAt: string
  updatedAt: string
}

export interface ApiArticleSummary {
  id: string
  slug: string
  title: string
  excerpt: string
  category: string
  tags: string[]
  coverImage?: string | null
  readingTime: number
  publishedAt: string | null
  published: boolean
  author: { id: string; name: string; avatar?: string | null }
  _count?: { comments: number }
}

export interface ApiComment {
  _id: string
  articleId: string
  author: string
  content: string
  createdAt: string
}

export interface ApiUser {
  _id: string
  email: string
  name: string
  role: string
}

export interface ApiAuthResponse {
  accessToken: string
  refreshToken: string
  user: ApiUser
}

export interface ApiArticlesResponse {
  articles: ApiArticleSummary[]
  pagination: {
    page: number
    limit: number
    total: number
    totalPages: number
  }
}

// ── Helpers ───────────────────────────────────────────────────────────────────

async function apiFetch<T>(
  endpoint: string,
  options: RequestInit = {}
): Promise<T> {
  const controller = new AbortController()
  const timeout = setTimeout(() => controller.abort(), TIMEOUT)

  try {
    const res = await fetch(`${API_URL}${endpoint}`, {
      ...options,
      signal: controller.signal,
      headers: {
        'Content-Type': 'application/json',
        ...options.headers,
      },
      credentials: 'include',
    })

    if (!res.ok) {
      const error = await res.json().catch(() => ({ message: res.statusText }))
      throw new Error(error.message || `HTTP ${res.status}`)
    }

    return res.json()
  } finally {
    clearTimeout(timeout)
  }
}

function getAuthHeader(): Record<string, string> {
  if (typeof window === 'undefined') return {}
  const token = localStorage.getItem('maiy_access_token')
  if (!token) return {}
  return { Authorization: `Bearer ${token}` }
}

// ── Articles ─────────────────────────────────────────────────────────────────

export async function fetchArticles(params?: {
  page?: number
  limit?: number
  category?: string
  tag?: string
  search?: string
}): Promise<ApiArticlesResponse> {
  const entries = Object.entries(params || {}).filter(
    ([, v]) => v !== undefined && v !== null
  )
  const qs = entries.length ? `?${new URLSearchParams(entries as [string, string][]).toString()}` : ''

  return apiFetch<ApiArticlesResponse>(`/api/articles${qs}`)
}

/** Admin: fetch all articles (published + unpublished) */
export async function fetchAdminArticles(): Promise<ApiArticleSummary[]> {
  const res = await apiFetch<ApiArticlesResponse>('/api/articles?published=all', {
    headers: getAuthHeader(),
  })
  return res.articles
}

/** Create a new article (admin only) */
export async function createArticle(data: {
  slug: string
  title: string
  excerpt: string
  content: string
  category: string
  tags: string[]
  coverImage?: string
  readingTime?: number
  published?: boolean
}): Promise<ApiArticle> {
  return apiFetch<ApiArticle>('/api/articles', {
    method: 'POST',
    headers: getAuthHeader(),
    body: JSON.stringify(data),
  })
}

/** Update an article (admin only) */
export async function updateArticle(
  id: string,
  data: Partial<{
  slug: string
  title: string
  excerpt: string
  content: string
  category: string
  tags: string[]
  coverImage?: string
  readingTime?: number
  published?: boolean
}>
): Promise<ApiArticle> {
  return apiFetch<ApiArticle>(`/api/articles/${id}`, {
    method: 'PUT',
    headers: getAuthHeader(),
    body: JSON.stringify(data),
  })
}

/** Delete an article (admin only) */
export async function deleteArticle(id: string): Promise<void> {
  await apiFetch(`/api/articles/${id}`, {
    method: 'DELETE',
    headers: getAuthHeader(),
  })
}

/** Toggle publish status (admin only) */
export async function togglePublish(id: string, published: boolean): Promise<ApiArticle> {
  return apiFetch<ApiArticle>(`/api/articles/${id}/publish`, {
    method: 'PATCH',
    headers: { ...getAuthHeader(), 'Content-Type': 'application/json' },
    body: JSON.stringify({ published }),
  })
}

/** Upload image (admin only) */
export async function uploadImage(file: File): Promise<{ url: string; publicId: string; width?: number; height?: number }> {
  const formData = new FormData()
  formData.append('file', file)
  const res = await fetch(`${API_URL}/api/upload/image`, {
    method: 'POST',
    headers: getAuthHeader(),
    body: formData,
    credentials: 'include',
  })
  if (!res.ok) {
    const err = await res.json().catch(() => ({ error: res.statusText }))
    throw new Error(err.error || `Upload failed: ${res.status}`)
  }
  return res.json()
}

/** Upload video (admin only) */
export async function uploadVideo(file: File): Promise<{ url: string; publicId: string; duration?: number }> {
  const formData = new FormData()
  formData.append('file', file)
  const res = await fetch(`${API_URL}/api/upload/video`, {
    method: 'POST',
    headers: getAuthHeader(),
    body: formData,
    credentials: 'include',
  })
  if (!res.ok) {
    const err = await res.json().catch(() => ({ error: res.statusText }))
    throw new Error(err.error || `Upload failed: ${res.status}`)
  }
  return res.json()
}

/** Search articles (uses backend search param + client-side tag fallback) */
export async function searchArticlesBackend(query: string, limit = 50): Promise<ApiArticleSummary[]> {
  const res = await apiFetch<ApiArticlesResponse>(
    `/api/articles?search=${encodeURIComponent(query)}&limit=${limit}`
  )
  return res.articles
}

export async function fetchArticle(slug: string): Promise<ApiArticle | null> {
  try {
    return await apiFetch<ApiArticle>(`/api/articles/${slug}`)
  } catch {
    return null
  }
}

export async function fetchComments(articleSlug: string): Promise<ApiComment[]> {
  try {
    return await apiFetch<ApiComment[]>(`/api/articles/${articleSlug}/comments`)
  } catch {
    return []
  }
}

// ── Auth ──────────────────────────────────────────────────────────────────────

export async function login(email: string, password: string): Promise<ApiAuthResponse> {
  return apiFetch<ApiAuthResponse>('/api/auth/login', {
    method: 'POST',
    body: JSON.stringify({ email, password }),
  })
}

export async function register(
  email: string,
  password: string,
  name: string
): Promise<ApiAuthResponse> {
  return apiFetch<ApiAuthResponse>('/api/auth/register', {
    method: 'POST',
    body: JSON.stringify({ email, password, name }),
  })
}

export async function logout(): Promise<void> {
  try {
    await apiFetch('/api/auth/logout', { method: 'POST' })
  } finally {
    if (typeof window !== 'undefined') {
      localStorage.removeItem('maiy_access_token')
      localStorage.removeItem('maiy_refresh_token')
    }
  }
}

// ── User ──────────────────────────────────────────────────────────────────────

export async function fetchCurrentUser(): Promise<ApiUser | null> {
  try {
    return await apiFetch<ApiUser>('/api/users/me', {
      headers: getAuthHeader(),
    })
  } catch {
    return null
  }
}

export async function updateProfile(data: Partial<ApiUser>): Promise<ApiUser> {
  return apiFetch<ApiUser>('/api/users/me', {
    method: 'PUT',
    headers: getAuthHeader(),
    body: JSON.stringify(data),
  })
}

// ── Newsletter ────────────────────────────────────────────────────────────────

export async function subscribeNewsletter(
  email: string,
  name?: string
): Promise<{ success: boolean; message: string }> {
  return apiFetch<{ success: boolean; message: string }>('/api/newsletter/subscribe', {
    method: 'POST',
    body: JSON.stringify({ email, name }),
  })
}

export async function unsubscribeNewsletter(
  email: string
): Promise<{ success: boolean; message: string }> {
  return apiFetch<{ success: boolean; message: string }>('/api/newsletter/unsubscribe', {
    method: 'POST',
    body: JSON.stringify({ email }),
  })
}

// ── Comments ─────────────────────────────────────────────────────────────────

export async function postComment(
  articleSlug: string,
  content: string,
  author: string
): Promise<ApiComment> {
  return apiFetch<ApiComment>(`/api/articles/${articleSlug}/comments`, {
    method: 'POST',
    headers: getAuthHeader(),
    body: JSON.stringify({ content, author }),
  })
}

export async function deleteComment(commentId: string): Promise<void> {
  await apiFetch(`/api/comments/${commentId}`, {
    method: 'DELETE',
    headers: getAuthHeader(),
  })
}

// ── Rooms ─────────────────────────────────────────────────────────────────────

export async function createRoom(
  name: string,
  description?: string
): Promise<{ code: string; name: string }> {
  return apiFetch('/api/rooms/create', {
    method: 'POST',
    headers: getAuthHeader(),
    body: JSON.stringify({ name, description }),
  })
}

export async function fetchRoom(code: string): Promise<any> {
  return apiFetch(`/api/rooms/${code}`)
}

// ── JWT Token helpers (client-side) ───────────────────────────────────────────

export function setTokens(accessToken: string, refreshToken?: string): void {
  if (typeof window === 'undefined') return
  localStorage.setItem('maiy_access_token', accessToken)
  if (refreshToken) localStorage.setItem('maiy_refresh_token', refreshToken)
}

export function getAccessToken(): string | null {
  if (typeof window === 'undefined') return null
  return localStorage.getItem('maiy_access_token')
}

export function clearTokens(): void {
  if (typeof window === 'undefined') return
  localStorage.removeItem('maiy_access_token')
  localStorage.removeItem('maiy_refresh_token')
}

'use client'

import { useEffect, useRef, useState, useCallback } from 'react'
import { io, Socket } from 'socket.io-client'

const SOCKET_URL = process.env.NEXT_PUBLIC_SITE_URL || 'http://localhost:3000'

export function useSocket() {
  const socketRef = useRef<Socket | null>(null)
  const [isConnected, setIsConnected] = useState(false)

  useEffect(() => {
    if (socketRef.current) return

    socketRef.current = io(SOCKET_URL, {
      transports: ['websocket', 'polling'],
      reconnection: true,
      reconnectionAttempts: 5,
      reconnectionDelay: 1000,
    })

    socketRef.current.on('connect', () => {
      setIsConnected(true)
    })

    socketRef.current.on('disconnect', () => {
      setIsConnected(false)
    })

    socketRef.current.on('connect_error', (err) => {
      console.warn('Socket connection error:', err.message)
      setIsConnected(false)
    })

    return () => {
      socketRef.current?.disconnect()
      socketRef.current = null
    }
  }, [])

  const joinRoom = useCallback((roomId: string, username: string) => {
    socketRef.current?.emit('join-room', { roomId, username })
  }, [])

  const leaveRoom = useCallback((roomId: string, username: string) => {
    socketRef.current?.emit('leave-room', { roomId, username })
  }, [])

  const syncPomodoro = useCallback(
    (roomId: string, timeLeft: number, phase: string, sessionCount: number) => {
      socketRef.current?.emit('pomodoro-tick', { roomId, timeLeft, phase, sessionCount })
    },
    []
  )

  return { socket: socketRef.current, isConnected, joinRoom, leaveRoom, syncPomodoro }
}

'use client'

import { useState, useEffect, useCallback, useRef } from 'react'

export type PomodoroPhase = 'work' | 'shortBreak' | 'longBreak'

export interface PomodoroState {
  timeLeft: number
  phase: PomodoroPhase
  sessionCount: number
  isRunning: boolean
  isPaused: boolean
}

export interface PomodoroConfig {
  workDuration: number       // in minutes (default: 25)
  shortBreakDuration: number // in minutes (default: 5)
  longBreakDuration: number  // in minutes (default: 15)
  sessionsUntilLongBreak: number // default: 4
}

const DEFAULT_CONFIG: PomodoroConfig = {
  workDuration: 25,
  shortBreakDuration: 5,
  longBreakDuration: 15,
  sessionsUntilLongBreak: 4,
}

export function usePomodoro(
  config: PomodoroConfig = DEFAULT_CONFIG,
  onTick?: (state: PomodoroState) => void,
  onPhaseChange?: (phase: PomodoroPhase, sessionCount: number) => void
) {
  const [timeLeft, setTimeLeft] = useState(config.workDuration * 60)
  const [phase, setPhase] = useState<PomodoroPhase>('work')
  const [sessionCount, setSessionCount] = useState(0)
  const [isRunning, setIsRunning] = useState(false)
  const [isPaused, setIsPaused] = useState(false)

  const intervalRef = useRef<NodeJS.Timeout | null>(null)
  const configRef = useRef(config)

  // Keep config ref updated
  useEffect(() => {
    configRef.current = config
  }, [config])

  const getPhaseDuration = useCallback((p: PomodoroPhase): number => {
    const cfg = configRef.current
    switch (p) {
      case 'work':
        return cfg.workDuration * 60
      case 'shortBreak':
        return cfg.shortBreakDuration * 60
      case 'longBreak':
        return cfg.longBreakDuration * 60
    }
  }, [])

  const getNextPhase = useCallback((): PomodoroPhase => {
    const cfg = configRef.current
    if (phase === 'work') {
      const newSessionCount = sessionCount + 1
      if (newSessionCount % cfg.sessionsUntilLongBreak === 0) {
        return 'longBreak'
      }
      return 'shortBreak'
    }
    return 'work'
  }, [phase, sessionCount])

  const stopTimer = useCallback(() => {
    if (intervalRef.current) {
      clearInterval(intervalRef.current)
      intervalRef.current = null
    }
  }, [])

  const tick = useCallback(() => {
    setTimeLeft((prev) => {
      if (prev <= 1) {
        return 0
      }
      return prev - 1
    })
  }, [])

  useEffect(() => {
    if (isRunning && !isPaused) {
      intervalRef.current = setInterval(tick, 1000)
    } else {
      stopTimer()
    }
    return stopTimer
  }, [isRunning, isPaused, tick, stopTimer])

  // Handle phase transitions
  useEffect(() => {
    if (timeLeft === 0 && isRunning) {
      const nextPhase = getNextPhase()
      const newSessionCount = phase === 'work' ? sessionCount + 1 : sessionCount

      setPhase(nextPhase)
      setSessionCount(newSessionCount)
      setTimeLeft(getPhaseDuration(nextPhase))

      onPhaseChange?.(nextPhase, newSessionCount)
    }
  }, [timeLeft, isRunning, phase, sessionCount, getNextPhase, getPhaseDuration, onPhaseChange])

  // Notify on tick
  useEffect(() => {
    if (isRunning) {
      onTick?.({ timeLeft, phase, sessionCount, isRunning, isPaused })
    }
  }, [timeLeft, phase, sessionCount, isRunning, isPaused, onTick])

  const start = useCallback(() => {
    setIsRunning(true)
    setIsPaused(false)
  }, [])

  const pause = useCallback(() => {
    setIsPaused(true)
  }, [])

  const resume = useCallback(() => {
    setIsPaused(false)
  }, [])

  const reset = useCallback(() => {
    stopTimer()
    setIsRunning(false)
    setIsPaused(false)
    setTimeLeft(getPhaseDuration(phase))
  }, [phase, getPhaseDuration, stopTimer])

  const skip = useCallback(() => {
    const nextPhase = getNextPhase()
    const newSessionCount = phase === 'work' ? sessionCount + 1 : sessionCount
    setPhase(nextPhase)
    setSessionCount(newSessionCount)
    setTimeLeft(getPhaseDuration(nextPhase))
    onPhaseChange?.(nextPhase, newSessionCount)
  }, [phase, sessionCount, getNextPhase, getPhaseDuration, onPhaseChange])

  const switchPhase = useCallback((newPhase: PomodoroPhase) => {
    stopTimer()
    setIsRunning(false)
    setIsPaused(false)
    setPhase(newPhase)
    setTimeLeft(getPhaseDuration(newPhase))
  }, [getPhaseDuration, stopTimer])

  const resetAll = useCallback(() => {
    stopTimer()
    setIsRunning(false)
    setIsPaused(false)
    setPhase('work')
    setSessionCount(0)
    setTimeLeft(config.workDuration * 60)
  }, [config.workDuration, stopTimer])

  return {
    // State
    timeLeft,
    phase,
    sessionCount,
    isRunning,
    isPaused,
    // Actions
    start,
    pause,
    resume,
    reset,
    skip,
    switchPhase,
    resetAll,
    // Helpers
    formatTime: (seconds: number) => {
      const mins = Math.floor(seconds / 60)
      const secs = seconds % 60
      return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`
    },
  }
}
